import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'
ChartJS.register(...registerables);

class Attending extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, usersResult: [], selectedValue: "", lastSortColumn: "", lastSortOrder: 0, paging: 0
        };
    }

    handleOnClickColumn = (column) => {
      console.log(column)

      var lastSortOrder = this.state.lastSortOrder

      if (column === this.state.lastSortColumn) {
        if (lastSortOrder === 0) {
          lastSortOrder = 1
        } else {
          lastSortOrder = 0
        }
      } else {
        lastSortOrder = 0
      }

      var results = this.state.results

      if (lastSortOrder === 0) {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return x < y ? -1 : x > y  ? 1: 0;
        })
      } else {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return y < x ? -1 : y > x  ? 1: 0;
        })
      }




      //console.log(results)
      this.setState({lastSortColumn: column})
      this.setState({lastSortOrder: lastSortOrder})
      this.setState({results: results})

    }







      componentDidMount() {


       var groupName = querystring.parse(window.location.search);
       this.setState({paging: 0})

        this.callVoalte(groupName.role)

      }



      callVoalte = (name) => {



        this.setState({lastSortColumn: ""})
        this.setState({lastSortOrder: 0})
        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getVoalteDevice?role=` + name, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }

      callBack = (number) => {
        var paging = this.state.paging + number
        this.setState({paging: paging})
      }



          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []

/*
              const roleOption = []


              this.state.results.map(rec => {
                roleOption.push({value: rec.name, label: rec.name})
              })

              console.log(this.state.selectedValue)

              content.push(<div style={{marginTop: "5px", display: "block"}}><Select
              value={this.state.selectedValue}
              name="role"
              options={roleOption}
              className="basic-multi-select"
              classNamePrefix="select"
              onChange={this.handleSelectChange}
            /></div>)


              var tableContent = []

              if (this.state.selectedValue.length > 0) {

                tableContent.push(<tr><td colspan="3">Role: {this.state.selectedValue}</td></tr>)
              }
              this.state.usersResult.map(rec => {
                  console.log(rec)
                  tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}>{rec.first_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.last_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.email_address}</td></tr>)
              })

         */







              //console.log(this.state.results)

            var tableContentformat = []

            var tableContent = []

            //var deviceGroup = []


              var graphLabel = []
              var personalPhone = []
              var clinCommPhone = []
              var unknownPhone = []
              var carePhone = []

              var startIndex = this.state.paging * 7
              var endIndex = startIndex + 6
              if (endIndex > this.state.results.length - 1) {
                endIndex = this.state.results.length - 1
              }

              while (startIndex <= endIndex) {

                var result = this.state.results[startIndex]
                var color = "black"
                var fontSize = "13px"

               // tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{rec3.unit}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{rec3.last_name}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{rec3.first_name}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{rec3.email_address}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{rec3.role_name}</span></td></tr>)

               graphLabel.push(result.loginTime)
                //Personal, Personal VoalteOne, CarePhone, ClinComm, Unknown




                var personalFilter = result.phone.filter(rec => rec.phone === "Personal")
                if (personalFilter.length > 0) {
                  personalPhone.push(personalFilter[0].percentage)
                } else {
                  personalPhone.push(0)
                }
                var clinCommFilter = result.phone.filter(rec => rec.phone === "ClinComm")
                if (clinCommFilter.length > 0) {
                  clinCommPhone.push(clinCommFilter[0].percentage)
                } else {
                  clinCommPhone.push(0)
                }
                var unknownFilter = result.phone.filter(rec => rec.phone === "Unknown")
                if (unknownFilter.length > 0) {
                  unknownPhone.push(unknownFilter[0].percentage)
                } else {
                  unknownPhone.push(0)
                }
                var carePhoneFilter = result.phone.filter(rec => rec.phone === "CarePhone")
                if (carePhoneFilter.length > 0) {
                  carePhone.push(carePhoneFilter[0].percentage)
                } else {
                  carePhone.push(0)
                }


                for (var index in result.items) {
                    var item = result.items[index]

                    var phoneColor = "black"
                    color = "black"
                    if (item.whatPhone == "Unknown") {
                        phoneColor = "red"
                        color = "red"
                    }


                    tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{result.loginTime}</span></td>
                    <td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{item.last_name}</span></td>
                    <td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{item.first_name}</span></td>
                    <td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{item.device_mac}</span></td>
                    <td style={{border: "1px solid", padding: "5px"}}><span style={{color: phoneColor, fontSize: fontSize}}>{item.whatPhone}</span></td>
                    <td style={{border: "1px solid", padding: "5px"}}><span style={{color: color, fontSize: fontSize}}>{item.client_type}</span></td></tr>)

                }


                startIndex += 1


              }



                  if (tableContent.length > 0) {
                    //&#x25B2; and &#x25BC;



                            /*
                    tableContentformat.push(<tr><td style={{border: "1px solid", padding: "5px"}}>
                      <button type="button" onClick={data => this.handleOnClickColumn("unit")}>Role/Unit</button>&nbsp;{col1}
                  </td><td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("last_name")}>Last Name</button>&nbsp;{col2}
                  </td><td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("first_name")}>First Name</button>&nbsp;{col3}
                  </td>
                  <td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("email_address")}>Email</button>&nbsp;{col4}
                  </td>
                  <td style={{border: "1px solid", padding: "5px"}}>
                        Role Name
                  </td>
                  </tr>)*/


                    tableContentformat.push(<tr>

                    <td style={{border: "1px solid", padding: "5px"}}>
                        Login Date
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                        Last Name
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                        First Name
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                        Device Mac
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                        Phone
                    </td>
                    <td style={{border: "1px solid", padding: "5px"}}>
                        Client Type
                    </td>
                    </tr>)


                    tableContent.map(rec4 => {
                        tableContentformat.push(rec4)
                    })


                }

                var groupName = querystring.parse(window.location.search)


                var previousButton = []
                var nextButton = []

                if (this.state.paging > 0) {
                  previousButton.push(<button onClick={() => this.callBack(-1)}>Back</button>)
                }

                if ((this.state.paging + 1) * 7  < this.state.results.length) {
                  nextButton.push(<button onClick={() => this.callBack(1)}>Next</button>)
                }

                content.push(<div style={{marginTop: "5px", display: "block"}}>{previousButton}&nbsp;&nbsp;{nextButton}</div>)

                content.push(<div><h2>{groupName.role}</h2></div>)


                content.push(<div><Bar 
                    height={400} 
                    width={400} 
                    data={{
                      labels: graphLabel,
                      datasets: [
                        {
                          label: 'Personal',
                          data: personalPhone,
                          backgroundColor: 'blue'
                        },
                        {
                          label: 'ClinComm',
                          data: clinCommPhone,
                          backgroundColor: 'green'
                        },
                        {
                          label: 'Unknown',
                          data: unknownPhone,
                          backgroundColor: 'orange'
                        },
                        {
                          label: 'CarePhone',
                          data: carePhone,
                          backgroundColor: 'purple'
                        }
                      ]


                    }} 
                    options={{maintainAspectRatio: false}}

                    ></Bar></div>)



                content.push(<table style={{marginTop: "5px"}}>{tableContentformat}</table>)

          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Attending
